import type { HREmployee } from '@/features/hr/types/hrTypes'

function pd(s: string): string {
  if (!s || s === '' || s === '0') return ''
  const p = String(s).trim().split('/')
  if (p.length !== 3) return ''
  const m  = p[0].padStart(2, '0')
  const d  = p[1].padStart(2, '0')
  const yy = parseInt(p[2])
  const yr = yy <= 30 ? 2000 + yy : 1900 + yy
  return `${yr}-${m}-${d}`
}

